def decide(ops: dict):
    if ops.get("incident"):
        if not ops.get("prev_model_id"):
            return "REQUEST_PREV_MODEL", "current_model"
        return "ROLLBACK", ops["prev_model_id"]
    return "STAY", "current_model"

