print(assess(valid), assess(invalid), assess(incomplete))

def decide(paths: list):
    needed = {"happy", "override", "ood_abstain"}
    if set(paths) != needed:
        return "REJECT_DEMO_PATHS", len(paths)
    return "CONTINUE", len(paths)

